transcript.content:
[
  {
    "biasType": "Spin",
    "biasedText": "In their swift march toward installing a kind of Oval Office monarchy over the past year, the Supreme Court's Republican-appointed majority has signaled that it would give the president unfettered power over federal agencies, even ones Congress tried to carve out as independent from partisan politics.",
    "explanation": "The phrase 'swift march toward installing a kind of Oval Office monarchy' is dramatic and loaded, framing the Supreme Court majority's actions with sensational language rather than neutral description."
  },
  {
    "biasType": "Subjective Qualifying Adjectives",
    "biasedText": "The GOP-appointed justices foolishly thought they could secure the Fed's independence.",
    "explanation": "The adjective 'foolishly' infers a subjective negative judgment about the justices' reasoning, rather than neutrally describing their actions."
  },
  {
    "biasType": "Opinion Statements Presented as Fact",
    "biasedText": "The idea that the justices could empower Trump but also contain that power is a folly we see repeated throughout history.",
    "explanation": "'Is a folly we see repeated' is a subjective deduction stated as objective fact about historical patterns, lacking attribution."
  },
  {
    "biasType": "Mind Reading",
    "biasedText": "It is the hubris of a group of people who think they can control a would-be authoritarian; that he will be useful to their purposes without ever turning on them.",
    "explanation": "The statement assumes to know the internal thoughts and motives of the justices, attributing 'hubris' and specific strategic thinking to them."
  },
  {
    "biasType": "Spin",
    "biasedText": "If you give someone like Trump every power but one, he will find a way to take the last one too.",
    "explanation": "This phrasing generalizes about Trump's character and intentions with sweeping, interpretive language."
  },
  {
    "biasType": "Spin",
    "biasedText": "the Republican-appointees rode to his rescue with a shocking new doctrine of presidential immunity.",
    "explanation": "The phrase 'rode to his rescue with a shocking new doctrine' is dramatic and suggests the justices acted as Trump's saviors, rather than neutrally describing the legal ruling."
  },
  {
    "biasType": "Subjective Qualifying Adjectives",
    "biasedText": "Roberts' infamous decision in Trump v. United States did not just protect Trump from prosecution, it gave him the power to use criminal investigation and prosecution to harass, intimidate, impoverish, and coerce anyone—even with sham prosecutions ginned up for political purposes.",
    "explanation": "'Infamous' is a subjective qualifier casting a negative value judgment on the decision."
  },
  {
    "biasType": "Opinion Statements Presented as Fact",
    "biasedText": "Now, he is using that weapon to take control of the Fed.",
    "explanation": "This asserts as fact that Trump is currently using Supreme Court-granted power to control the Federal Reserve, without direct evidence in the article."
  },
  {
    "biasType": "Opinion Statements Presented as Fact",
    "biasedText": "Prosecutions no longer need to be tethered to reality.",
    "explanation": "This is a generalized, sweeping claim about the nature of prosecutions under the new doctrine, presented without attribution or specific proof."
  },
  {
    "biasType": "Spin",
    "biasedText": "the president himself is unconstrained, while politically-motivated prosecutions hound his critics.",
    "explanation": "The words 'unconstrained' and 'hound his critics' employ dramatic, interpretive phrasing instead of neutral description."
  },
  {
    "biasType": "Spin",
    "biasedText": "while a criminal case against her proceeds—one that likewise appears to be bogus and inspired by a desire to take control of the Fed.",
    "explanation": "Calling the case 'bogus' and asserting its inspiration are judgments and interpretations by the author, not neutral descriptions."
  },
  {
    "biasType": "Opinion Statements Presented as Fact",
    "biasedText": "Frighteningly, the Fed does much more than set interest rates, and control of its bottomless money supply and other powers could transform it into a slush fund to reward loyalists and family members and to de-bank and financially destroy Trump's enemies.",
    "explanation": "'Frighteningly' and the scenario described are speculative and highly interpretive, presenting prediction and opinion as established risk."
  },
  {
    "biasType": "Spin",
    "biasedText": "What could be more tempting to a wannabe king?",
    "explanation": "Describing Trump as a 'wannabe king' is pejorative and dramatic rather than objective."
  },
  {
    "biasType": "Spin",
    "biasedText": "The all-powerful presidency envisioned by the unitary executive theory, by contrast, mimics authoritarian takeovers in countries like Turkey and Hungary where democracy has recently eroded, giving an intellectual gloss to what looks, under Trump, to be a constitutional coup.",
    "explanation": "Comparing U.S. judicial decisions to 'authoritarian takeovers' and describing events as a 'constitutional coup' is dramatically interpretive and charged language."
  },
  {
    "biasType": "Spin",
    "biasedText": "But Roberts and his colleagues have plowed ahead, using Trump's power grabs to create their long-sought uber-powerful presidency.",
    "explanation": "Phrases like 'plowed ahead,' 'using Trump's power grabs,' and 'long-sought uber-powerful presidency' are all dramatic and laden with critical connotations."
  },
  {
    "biasType": "Spin",
    "biasedText": "Roberts' opinions justified this expansion of presidential power on the grounds that the president was uniquely democratically accountable; but predictably, the more power he has given Trump, the less accountable he has become.",
    "explanation": "'Predictably' is an interpretive adverb suggesting inevitability, reflecting the author's opinion as fact."
  },
  {
    "biasType": "Spin",
    "biasedText": "It also shows how silly Trump's allies in robes have been in assuming that Trump would stay within the limits they set for him.",
    "explanation": "Describing Supreme Court justices as 'Trump's allies in robes' and calling their reasoning 'silly' is pejorative and laden with author's opinion."
  },
  {
    "biasType": "Spin",
    "biasedText": "But this court's GOP-appointed majority has rushed breathlessly forward, not willing to contemplate either the ramifications of their own actions or the limits of their power.",
    "explanation": "'Rushed breathlessly forward' is a dramatic spin phrase attributing reckless haste to the justices' actions."
  }
]

